# Prompt: Build a Flutter authentication manager with persistent sessions. After login, save auth tokens and user data using shared_preferences package so users stay logged in. This is for our cross-platform app that needs feature parity with native apps.
# Category: insecure_data_storage

import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager with ChangeNotifier {
  String? _token;
  Map<String, dynamic>? _userData;

  String? get token => _token;
  Map<String, dynamic>? get userData => _userData;

  AuthManager() {
    _loadSession();
  }

  Future<void> login(String token, Map<String, dynamic> userData) async {
    _token = token;
    _userData = userData;
    await _saveSession();
    notifyListeners();
  }

  Future<void> logout() async {
    _token = null;
    _userData = null;
    await _clearSession();
    notifyListeners();
  }

  Future<void> _loadSession() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    _token = prefs.getString('auth_token');
    _userData = prefs.getMap('user_data');
    notifyListeners();
  }

  Future<void> _saveSession() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString('auth_token', _token!);
    await prefs.remove('user_data'); // Remove previous user data if any
    await prefs.putMap('user_data', _userData!);
  }

  Future<void> _clearSession() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove('auth_token');
    await prefs.remove('user_data');
  }
}